/**
 * @param {string[]} chunks
 * @param {string[]} queries
 * @return {number[]}
 */
function solve(chunks, queries) {
    const s = chunks.join('');
    const n = s.length;

    // 1. Identify all valid "words" in s and count their occurrences.
    // A word is a maximal contiguous sequence of characters that are either
    // lowercase letters or are surrounded by letters with a hyphen.

    // We iterate through the string and extract all maximal sequences that form valid words.

    const wordCounts = new Map();

    let i = 0;
    while (i < n) {
        // Skip separators (characters that are not letters and not allowed hyphens)
        if (!/[a-z]/.test(s[i]) && s[i] !== '-') {
            i++;
            continue;
        }

        // Start of a potential word segment
        let start = i;
        let currentSegment = '';
        let j = i;

        while (j < n) {
            const char = s[j];
            const isLetter = /[a-z]/.test(char);

            if (isLetter) {
                currentSegment += char;
                j++;
            } else if (char === '-') {
                // Hyphen is only allowed if it's between two letters.
                // We need to check the context in the *original* string s.
                // Since we are building the maximal sequence, we check if the surrounding characters in s are letters.

                // Check left neighbor (if it's part of the current segment or the character just before it)
                const leftChar = j > 0 ? s[j - 1] : null;
                // Check right neighbor (if it's part of the sequence we are about to process)
                const rightChar = j + 1 < n ? s[j + 1] : null;

                if (leftChar && /[a-z]/.test(leftChar) && rightChar && /[a-z]/.test(rightChar)) {
                    // Valid internal hyphen
                    currentSegment += char;
                    j++;
                } else {
                    // Invalid hyphen or hyphen at boundary of a potential word
                    // This segment ends before this hyphen.
                    break;
                }
            } else {
                // Any other separator
                break;
            }
        }

        // The sequence s[start...j-1] is the maximal segment containing letters and allowed hyphens starting at 'start'.
        let potentialWord = s.substring(start, j);

        // Now, we must validate if this potentialWord itself is a valid word according to the definition:
        // "it is not a part of some longer valid word" (This is handled by finding maximal segments).
        // And the internal structure must be valid (handled by the loop condition).

        // The crucial part is that the definition implies we must extract maximal sequences 
        // composed only of letters and properly placed hyphens.

        if (potentialWord.length > 0) {
            // We must verify that every character in potentialWord is either a letter or a hyphen
            // correctly surrounded by letters *within the word*.
            let isValidWord = true;
            for (let k = 0; k < potentialWord.length; k++) {
                const char = potentialWord[k];
                if (/[a-z]/.test(char)) continue;
                if (char === '-') {
                    const left = potentialWord[k - 1];
                    const right = potentialWord[k + 1];
                    if (!left || !/[a-z]/.test(left) || !right || !/[a-z]/.test(right)) {
                        isValidWord = false;
                        break;
                    }
                } else {
                    // Should not happen if the initial skip was correct, but for safety.
                    isValidWord = false;
                    break;
                }
            }

            if (isValidWord) {
                // This maximal segment is a valid word.
                wordCounts.set(potentialWord, (wordCounts.get(potentialWord) || 0) + 1);
            }
        }

        // Move 'i' to the character after the processed segment
        i = j;
    }

    // 2. Process queries
    const results = [];
    for (const query of queries) {
        results.push(wordCounts.get(query) || 0);
    }

    return results;
}

