fun solve(chunks: Array<String>, queries: Array<String>): Array<Long> {
    val s = chunks.joinToString("")
    val n = s.length

    // Map to store the count of each valid word
    val wordCounts = mutableMapOf<String, Long>()

    var i = 0
    while (i < n) {
        // Skip non-word starting characters (anything that isn't a letter or a hyphen)
        if (!s[i].isLetter() && s[i] != '-') {
            i++
            continue
        }

        // Potential start of a word segment
        var start = i
        var j = i

        // Try to extend the segment as long as it's composed of letters or valid hyphens
        while (j < n) {
            val char = s[j]

            if (char.isLetter()) {
                j++
                continue
            } else if (char == '-') {
                // Check hyphen validity: must be surrounded by letters *within the maximal sequence*
                // Since we are building the maximal segment s[start...j], we check neighbors in s.

                // Check left neighbor (must be a letter within the potential word, i.e., s[j-1])
                val leftIsLetter = j > start && s[j - 1].isLetter()

                // Check right neighbor (must be a letter in s[j+1])
                val rightIsLetter = j + 1 < n && s[j + 1].isLetter()

                if (leftIsLetter && rightIsLetter) {
                    j++ // Include the hyphen
                    continue
                } else {
                    // Invalid hyphen context for forming a maximal word segment
                    break
                }
            } else {
                // Other separator character
                break
            }
        }

        // The maximal segment found is s[start...j-1]
        val potentialWord = s.substring(start, j)

        if (potentialWord.isNotEmpty()) {
            // A crucial step: Ensure the extracted segment is indeed a valid "word"
            // according to the definition: "it is not a part of some longer valid word."
            // Our loop structure (finding maximal sequences delimited by invalid chars/hyphens)
            // should guarantee maximality, provided the segment structure is valid.

            // We must verify the structure of the found potentialWord itself:
            // 1. Must only contain letters and hyphens. (Guaranteed by loop condition if we trust the break logic)
            // 2. Every hyphen must be surrounded by letters *within* the word.
            var isValidWordStructure = true
            for (k in potentialWord.indices) {
                val char = potentialWord[k]
                if (char == '-') {
                    // Check neighbors within the word itself
                    val leftChar = if (k > 0) potentialWord[k - 1] else null
                    val rightChar = if (k < potentialWord.length - 1) potentialWord[k + 1] else null

                    if (leftChar == null || rightChar == null || !leftChar.isLetter() || !rightChar.isLetter()) {
                        isValidWordStructure = false
                        break
                    }
                }
            }

            if (isValidWordStructure) {
                // This maximal segment is a valid word. Count it.
                wordCounts[potentialWord] = wordCounts.getOrDefault(potentialWord, 0L) + 1
            }
        }

        // Move 'i' to the character after the processed segment (j)
        i = j
    }

    // 2. Process queries
    val results = mutableListOf<Long>()
    for (query in queries) {
        // Per the constraints, queries[i] is guaranteed to be a valid word structure, 
        // but we only count occurrences found in s.
        results.add(wordCounts.getOrDefault(query, 0L))
    }

    return results.toTypedArray()
}
